import { unstable_cache } from 'next/cache';

export type Post = {
  id: number;
  title: string;
  content: string;
};

// In-memory store (in production, use a database)
const store: Post[] = [
  { id: 1, title: 'First Post', content: 'Welcome to the blog!' },
];

/**
 * Add a new post to the store.
 * Called by the Server Action before cache invalidation.
 */
export function addPost(title: string, content: string): Post {
  const id = store.length > 0 ? Math.max(...store.map((p) => p.id)) + 1 : 1;
  const post: Post = { id, title, content };
  store.push(post);
  return post;
}

/**
 * Retrieve all posts, cached under the "posts" tag.
 * When `revalidateTag('posts')` is called (e.g. after creating a new post),
 * the next invocation will re-execute the callback and return fresh data.
 */
export const getPosts = unstable_cache(
  async (): Promise<Post[]> => {
    // Simulate a database query delay so the cache effect is observable
    return [...store];
  },
  ['posts-list'],
  { tags: ['posts'] }
);

'use server';

import { revalidateTag } from 'next/cache';
import { redirect } from 'next/navigation';
import { addPost } from '@/lib/posts';

/**
 * Server Action — creates a new post, then invalidates the "posts"
 * cache tag so the next page render fetches fresh data instead of
 * serving stale cached content.
 */
export async function createPost(formData: FormData) {
  const title = formData.get('title') as string;
  const content = formData.get('content') as string;

  if (!title?.trim() || !content?.trim()) {
    throw new Error('Title and content are required');
  }

  // Persist the new post
  addPost(title.trim(), content.trim());

  /*
   * Invalidate every cache entry tagged with "posts".
   *
   * Because this is followed by a server-side redirect, the
   * subsequent render of the page will re-execute the
   * `unstable_cache` callback (in lib/posts.ts) rather than
   * serving stale data — guaranteeing the user always sees
   * up-to-date content after submitting the form.
   */
  revalidateTag('posts');

  // Navigate back to the home page; the render will fetch fresh data.
  redirect('/');
}

import { getPosts } from '@/lib/posts';
import { createPost } from './actions';

export default async function HomePage() {
  // The data is cached under the "posts" tag via unstable_cache.
  // After createPost runs, revalidateTag('posts') ensures this
  // call always returns fresh data on the next page render.
  const posts = await getPosts();

  return (
    <main>
      <h1>Posts</h1>

      <form action={createPost}>
        <div>
          <label htmlFor="title">Title</label>
          <input id="title" name="title" placeholder="Post title" required />
        </div>
        <div>
          <label htmlFor="content">Content</label>
          <textarea
            id="content"
            name="content"
            placeholder="Post content"
            required
          />
        </div>
        <button type="submit">Create Post</button>
      </form>

      {posts.length === 0 ? (
        <p>No posts yet.</p>
      ) : (
        <ul>
          {posts.map((post) => (
            <li key={post.id}>
              <h2>{post.title}</h2>
              <p>{post.content}</p>
            </li>
          ))}
        </ul>
      )}
    </main>
  );
}

