4	import { redirect } from 'next/navigation';
5	import { addPost } from '@/lib/posts';
6	
7	/**
8	 * Server Action — creates a new post, then updates the "posts"
9	 * cache tag so the very next page render fetches fresh data instead of
10	 * serving stale cached content.
11	 *
12	 * `updateTag` is preferred over `revalidateTag` here because:
13	 *  1. It provides read-your-own-writes semantics — the next render
14	 *     waits for fresh data before completing.
15	 *  2. It can only be called from within a Server Action, which fits
16	 *     our usage exactly.
17	 *  3. It guarantees no stale content is served to the user.
18	 */
19	export async function createPost(formData: FormData) {
20	  const title = formData.get('title') as string;
21	  const content = formData.get('content') as string;
22	
23	  if (!title?.trim() || !content?.trim()) {
24	    throw new Error('Title and content are required');
25	  }
26	
27	  // Persist the new post
28	  addPost(title.trim(), content.trim());
29	
30	  /*
31	   * Update the "posts" cache tag with read-your-own-writes semantics.
32	   *
33	   * Because this is followed by a server-side redirect, the
34	   * subsequent render of the page will re-execute the
35	   * `unstable_cache` callback (in lib/posts.ts) with fresh data
36	   * before responding — guaranteeing the user always sees
37	   * up-to-date content after submitting the form.
38	   */
39	  updateTag('posts');
40	
41	  // Navigate back to the home page; the render will fetch fresh data.
42	  redirect('/');
43	}
