3	export type Post = {
4	  id: number;
5	  title: string;
6	  content: string;
7	};
8	
9	// In-memory store (in production, use a database)
10	const store: Post[] = [
11	  { id: 1, title: 'First Post', content: 'Welcome to the blog!' },
12	];
13	
14	/**
15	 * Add a new post to the store.
16	 * Called by the Server Action before cache invalidation.
17	 */
18	export function addPost(title: string, content: string): Post {
19	  const id = store.length > 0 ? Math.max(...store.map((p) => p.id)) + 1 : 1;
20	  const post: Post = { id, title, content };
21	  store.push(post);
22	  return post;
23	}
