25	/**
26	 * Retrieve all posts, cached under the "posts" tag.
27	 * When `revalidateTag('posts')` is called (e.g. after creating a new post),
28	 * the next invocation will re-execute the callback and return fresh data.
29	 */
30	export const getPosts = unstable_cache(
31	  async (): Promise<Post[]> => {
32	    // Simulate a database query delay so the cache effect is observable
33	    return [...store];
34	  },
35	  ['posts-list'],
36	  { tags: ['posts'] }
37	);
